### Wrapping Effects in custom Hooks {/_wrapping-effects-in-custom-hooks_ /}

Effects are an "escape hatch": you use them when you need to "step outside React" and when there is no better built-in solution for your use case. If you find yourself often needing to manually write Effects, it's usually a sign that you need to extract some custom Hooks for common behaviors your components rely on.

For example, this `useChatRoom` custom Hook "hides" the logic of your Effect behind a more declarative API:


    function useChatRoom({ serverUrl, roomId }) {
      useEffect(() => {
        const options = {
          serverUrl: serverUrl,
          roomId: roomId
        };
        const connection = createConnection(options);
        connection.connect();
        return () => connection.disconnect();
      }, [roomId, serverUrl]);
    }

Then you can use it from any component like this:


    function ChatRoom({ roomId }) {
      const [serverUrl, setServerUrl] = useState('https://localhost:1234');

      useChatRoom({
        roomId: roomId,
        serverUrl: serverUrl
      });
      // ...

There are also many excellent custom Hooks for every purpose available in the React ecosystem.

Learn more about wrapping Effects in custom Hooks.

#### Custom `useChatRoom` Hook {/_custom-usechatroom-hook_ /}

This example is identical to one of the earlier examples, but the logic is extracted to a custom Hook.


    import { useState } from 'react';
    import { useChatRoom } from './useChatRoom.js';

    function ChatRoom({ roomId }) {
      const [serverUrl, setServerUrl] = useState('https://localhost:1234');

      useChatRoom({
        roomId: roomId,
        serverUrl: serverUrl
      });

      return (
        <>
          <label>
            Server URL:{' '}
            <input
              value={serverUrl}
              onChange={e => setServerUrl(e.target.value)}
            />
          </label>
          <h1>Welcome to the {roomId} room!</h1>
        </>
      );
    }

    export default function App() {
      const [roomId, setRoomId] = useState('general');
      const [show, setShow] = useState(false);
      return (
        <>
          <label>
            Choose the chat room:{' '}
            <select
              value={roomId}
              onChange={e => setRoomId(e.target.value)}
            >
              <option value="general">general</option>
              <option value="travel">travel</option>
              <option value="music">music</option>
            </select>
          </label>
          <button onClick={() => setShow(!show)}>
            {show ? 'Close chat' : 'Open chat'}
          </button>
          {show && <hr />}
          {show && <ChatRoom roomId={roomId} />}
        </>
      );
    }


    import { useEffect } from 'react';
    import { createConnection } from './chat.js';

    export function useChatRoom({ serverUrl, roomId }) {
      useEffect(() => {
        const connection = createConnection(serverUrl, roomId);
        connection.connect();
        return () => {
          connection.disconnect();
        };
      }, [roomId, serverUrl]);
    }


    export function createConnection(serverUrl, roomId) {
      // A real implementation would actually connect to the server
      return {
        connect() {
          console.log('✅ Connecting to "' + roomId + '" room at ' + serverUrl + '...');
        },
        disconnect() {
          console.log('❌ Disconnected from "' + roomId + '" room at ' + serverUrl);
