          pointerEvents: 'none',
          left: -20,
          top: -20,
          width: 40,
          height: 40,
        }} />
      );
    }


    import { useState, useEffect } from 'react';

    export function useWindowListener(eventType, listener) {
      useEffect(() => {
        window.addEventListener(eventType, listener);
        return () => {
          window.removeEventListener(eventType, listener);
        };
      }, [eventType, listener]);
    }


